def compute_signal(snapshot, params):
    threshold = params.get("threshold", 0.7)
    best_bid_depth = snapshot.get("best_bid_depth", 0.0)
    best_ask_depth = snapshot.get("best_ask_depth", 0.0)
    total_depth = best_bid_depth + best_ask_depth
    if total_depth == 0.0:
        return None
    imbalance = (best_bid_depth - best_ask_depth) / total_depth
    if imbalance > threshold:
        return -1.0
    if imbalance < -threshold:
        return 1.0
    return None
